module top_module(
    input wire ck_in,
    input wire enable,
    output wire ck_out
);wire ck_inb;
reg enl;

assign ck_inb = ~ck_in;
always @(ck_inb or enable)
if (ck_inb)
    enl = enable;
  wire temp1_ck_in = ck_in;
  wire temp2_enl = enl;
  assign ck_out = temp1_ck_in & temp2_enl;

endmodule
